export default function (attributes, additionalConfig = {}) {
    return Object.keys(additionalConfig).reduce((res, key) => {
        const attribute = attributes.find((attr) => attr.key === key);
        if (attribute) {
            const transformedAttribute = {
                ...attribute,
                // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
                ...additionalConfig[key],
            };
            res.push(transformedAttribute);
        }
        else {
            // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
            res.push({ key, ...additionalConfig[key] });
        }
        return res;
    }, []);
}
